import React, {  useState } from 'react';

import './home.css';  // Assurez-vous de lier le fichier CSS

function Home() {
    const [user, setUser] = useState({
        name: "Kekli Abdesslem",
        bio: "Technicien support IT passionné par les réseaux et la technologie.",
        profilePicture: "https://via.placeholder.com/150", // Image par défaut
        coverPhoto: "https://via.placeholder.com/800x300", // Image de couverture par défaut
      });

      const [showModal, setShowModal] = useState(false);
      const [editName, setEditName] = useState(user.name);
      const [editBio, setEditBio] = useState(user.bio);

      // Fonction pour convertir une image en Base64
      const convertToBase64 = (file, callback) => {
        const reader = new FileReader();
        reader.onload = () => {
          callback(reader.result);
        };
        reader.readAsDataURL(file);
      };

      const handleProfilePictureChange = (event) => {
        const file = event.target.files[0];
        if (file) {
          convertToBase64(file, (base64) => {
            setUser({ ...user, profilePicture: base64 });
          });
        }
      };

      const handleCoverPhotoChange = (event) => {
        const file = event.target.files[0];
        if (file) {
          convertToBase64(file, (base64) => {
            setUser({ ...user, coverPhoto: base64 });
          });
        }
      };

      const handleEdit = () => {
        setUser({ ...user, name: editName, bio: editBio });
        setShowModal(false);
      };

      const handleDelete = () => {
        const confirmDelete = window.confirm(
          "Êtes-vous sûr de vouloir supprimer votre compte ?"
        );
        if (confirmDelete) {
          alert("Votre compte a été supprimé !");
          // Logique supplémentaire pour la suppression
        }
      };

      return (
        <div style={styles.container}>
          {/* Couverture */}
          <div style={styles.coverPhotoContainer}>
            <img src={user.coverPhoto} alt="Couverture" style={styles.coverPhoto} />
            <label style={styles.uploadCoverLabel}>
              Changer la couverture
              <input
                type="file"
                style={{ display: 'none' }}
                onChange={handleCoverPhotoChange}
              />
            </label>
            <img
              src={user.profilePicture}
              alt="Profil utilisateur"
              style={styles.profilePicture}
            />
            <label style={styles.uploadProfileLabel}>
              Changer la photo
              <input
                type="file"
                style={{ display: 'none' }}
                onChange={handleProfilePictureChange}
              />
            </label>
          </div>

          {/* Informations utilisateur */}
          <div style={styles.infoSection}>
            <h2 style={styles.userName}>{user.name}</h2>
            <p style={styles.userBio}>{user.bio}</p>
          </div>

          {/* Boutons pour modifier et supprimer */}
          <div style={styles.actionButtons}>
            <button style={styles.editButton} onClick={() => setShowModal(true)}>
              Modifier le profil
            </button>
            <button style={styles.deleteButton} onClick={handleDelete}>
              Supprimer mon compte
            </button>
          </div>

          {/* Modale pour modifier le profil */}
          {showModal && (
            <div style={styles.modalOverlay}>
              <div style={styles.modal}>
                <h2>Modifier le profil</h2>
                <div style={styles.modalField}>
                  <label>Nom :</label>
                  <input
                    type="text"
                    value={editName}
                    onChange={(e) => setEditName(e.target.value)}
                    style={styles.input}
                  />
                </div>
                <div style={styles.modalField}>
                  <label>Bio :</label>
                  <textarea
                    value={editBio}
                    onChange={(e) => setEditBio(e.target.value)}
                    style={styles.textarea}
                  ></textarea>
                </div>
                <div style={styles.modalActions}>
                  <button style={styles.saveButton} onClick={handleEdit}>
                    Sauvegarder
                  </button>
                  <button style={styles.cancelButton} onClick={() => setShowModal(false)}>
                    Annuler
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      );
    };

    const styles = {
      container: {
        fontFamily: 'Arial, sans-serif',
        width: '90%',
        margin: '20px auto',
        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.2)',
        borderRadius: '10px',
        overflow: 'hidden',
        backgroundColor: '#fff',
      },
      coverPhotoContainer: {
        position: 'relative',
        height: '300px',
        backgroundColor: '#f0f0f0',
      },
      coverPhoto: {
        width: '100%',
        height: '100%',
        objectFit: 'cover',
      },
      profilePicture: {
        position: 'absolute',
        bottom: '-50px',
        left: '20px',
        width: '100px',
        height: '100px',
        borderRadius: '50%',
        border: '4px solid #fff',
      },
      uploadProfileLabel: {
        position: 'absolute',
        bottom: '0',
        left: '140px',
        backgroundColor: '#007bff',
        color: '#fff',
        padding: '5px 10px',
        borderRadius: '5px',
        cursor: 'pointer',
        fontSize: '12px',
      },
      uploadCoverLabel: {
        position: 'absolute',
        top: '10px',
        right: '10px',
        backgroundColor: '#007bff',
        color: '#fff',
        padding: '5px 10px',
        borderRadius: '5px',
        cursor: 'pointer',
        fontSize: '12px',
      },
      infoSection: {
        padding: '60px 20px 20px',
        textAlign: 'left',
      },
      userName: {
        fontSize: '24px',
        fontWeight: '#555',
      },
      userBio: {
        fontSize: '14px',
        color: '#555',
        margin: '10px 0',
      },
      actionButtons: {
        display: 'flex',
        justifyContent: 'space-between',
        padding: '20px',
        borderTop: '1px solid #ddd',
      },
      editButton: {
        padding: '10px 20px',
        backgroundColor: '#007bff',
        color: '#fff',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer',
      },
      deleteButton: {
        padding: '10px 20px',
        backgroundColor: '#ff4d4f',
        color: '#fff',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer',
      },
      modalOverlay: {
        position: 'fixed',
        top: '0',
        left: '0',
        width: '100%',
        height: '100%',
        backgroundColor: 'rgba(0, 0, 0, 0.5)',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
      },
      modal: {
        width: '400px',
        backgroundColor: '#fff',
        borderRadius: '10px',
        padding: '20px',
        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.2)',
        textAlign: 'center',
      },
      modalField: {
        marginBottom: '15px',
        textAlign: 'left',
      },
      input: {
        width: '100%',
        padding: '8px',
        marginTop: '5px',
        borderRadius: '5px',
        border: '1px solid #ddd',
      },
      textarea: {
        width: '100%',
        padding: '8px',
        marginTop: '5px',
        borderRadius: '5px',
        border: '1px solid #ddd',
      },
      modalActions: {
        display: 'flex',
        justifyContent: 'space-between',
      },
      saveButton: {
        padding: '10px 20px',
        backgroundColor: '#007bff',
        color: '#fff',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer',
      },
      cancelButton: {
        padding: '10px 20px',
        backgroundColor: '#ff4d4f',
        color: '#fff',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer',
      },
    };

export default Home;
